#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_PROCESSES 5
#define MAX_RESOURCES 3

typedef struct {
 int available[MAX_RESOURCES];
 int maximum[MAX_PROCESSES][MAX_RESOURCES];
 int allocation[MAX_PROCESSES][MAX_RESOURCES];
 int need[MAX_PROCESSES][MAX_RESOURCES];
 int num_processes;
 int num_resources;
} BankerSystem;

// Function prototypes
void initialize_system(BankerSystem *banker, int available[], 
 int maximum[][MAX_RESOURCES], 
 int allocation[][MAX_RESOURCES],
 int num_processes, int num_resources);

void calculate_need(BankerSystem *banker);

bool is_safe(BankerSystem *banker, int safe_sequence[]);

bool request_resources(BankerSystem *banker, int process_id, 
 int request[]);

void print_state(BankerSystem *banker);

// Initialize the banker's algorithm system
void initialize_system(BankerSystem *banker, int available[], 
 int maximum[][MAX_RESOURCES], 
 int allocation[][MAX_RESOURCES],
 int num_processes, int num_resources) {

 banker->num_processes = num_processes;
 banker->num_resources = num_resources;

 // Copy available resources
 for (int j = 0; j < num_resources; j++) {
 banker->available[j] = available[j];
 }

 // Copy maximum and allocation matrices
 for (int i = 0; i < num_processes; i++) {
 for (int j = 0; j < num_resources; j++) {
 banker->maximum[i][j] = maximum[i][j];
 banker->allocation[i][j] = allocation[i][j];
 }
 }

 // Calculate need matrix
 calculate_need(banker);
}

// Calculate Need = Maximum - Allocation
void calculate_need(BankerSystem *banker) {
 for (int i = 0; i < banker->num_processes; i++) {
 for (int j = 0; j < banker->num_resources; j++) {
 banker->need[i][j] = banker->maximum[i][j] - banker->allocation[i][j];
 }
 }
}

// Check if system is in safe state
bool is_safe(BankerSystem *banker, int safe_sequence[]) {
 int work[MAX_RESOURCES];
 bool finish[MAX_PROCESSES];

 // Initialize work = available
 for (int j = 0; j < banker->num_resources; j++) {
 work[j] = banker->available[j];
 }

 // Initialize all processes as not finished
 for (int i = 0; i < banker->num_processes; i++) {
 finish[i] = false;
 }

 int count = 0;

 // Find a process that can complete
 while (count < banker->num_processes) {
 bool found = false;

 for (int i = 0; i < banker->num_processes; i++) {
 if (!finish[i]) {
 // Check if process i's needs can be satisfied
 bool can_finish = true;
 for (int j = 0; j < banker->num_resources; j++) {
 if (banker->need[i][j] > work[j]) {
 can_finish = false;
 break;
 }
 }

 if (can_finish) {
 // Process can finish, release its resources
 for (int j = 0; j < banker->num_resources; j++) {
 work[j] += banker->allocation[i][j];
 }
 finish[i] = true;
 safe_sequence[count] = i;
 count++;
 found = true;
 }
 }
 }

 // No process could finish - deadlock possible
 if (!found) {
 return false;
 }
 }

 return true; // Safe state
}

// Request resources with deadlock avoidance
bool request_resources(BankerSystem *banker, int process_id, 
 int request[]) {

 // Step 1: Check if request exceeds process's need
 for (int j = 0; j < banker->num_resources; j++) {
 if (request[j] > banker->need[process_id][j]) {
 printf("Error: Process P%d exceeds maximum claim!\n", process_id);
 return false;
 }
 }

 // Step 2: Check if request exceeds available resources
 for (int j = 0; j < banker->num_resources; j++) {
 if (request[j] > banker->available[j]) {
 printf("P%d must wait - insufficient resources available.\n", process_id);
 return false;
 }
 }

 // Step 3: Temporarily allocate resources
 for (int j = 0; j < banker->num_resources; j++) {
 banker->available[j] -= request[j];
 banker->allocation[process_id][j] += request[j];
 banker->need[process_id][j] -= request[j];
 }

 // Step 4: Check if new state is safe
 int safe_sequence[MAX_PROCESSES];

 if (is_safe(banker, safe_sequence)) {
 printf("Request GRANTED to P%d - System remains safe.\n", process_id);
 printf("Safe sequence: ");
 for (int i = 0; i < banker->num_processes; i++) {
 printf("P%d ", safe_sequence[i]);
 }
 printf("\n");
 return true;
 } else {
 // Rollback: restore previous state
 for (int j = 0; j < banker->num_resources; j++) {
 banker->available[j] += request[j];
 banker->allocation[process_id][j] -= request[j];
 banker->need[process_id][j] += request[j];
 }
 printf("Request DENIED for P%d - Would lead to unsafe state!\n", process_id);
 return false;
 }
}

// Print current system state
void print_state(BankerSystem *banker) {
 printf("\n=== Current System State ===\n");
 printf("Available: [");
 for (int j = 0; j < banker->num_resources; j++) {
 printf("%d ", banker->available[j]);
 }
 printf("]\n\n");

 printf("Process | Maximum | Allocated | Need \n");
 printf("--------|--------------|-------------|--------------\n");

 for (int i = 0; i < banker->num_processes; i++) {
 printf("P%d | ", i);
 for (int j = 0; j < banker->num_resources; j++) {
 printf("%d ", banker->maximum[i][j]);
 }
 printf(" | ");
 for (int j = 0; j < banker->num_resources; j++) {
 printf("%d ", banker->allocation[i][j]);
 }
 printf(" | ");
 for (int j = 0; j < banker->num_resources; j++) {
 printf("%d ", banker->need[i][j]);
 }
 printf("\n");
 }
}

int main() {
 // System configuration: 3 resource types
 int available[] = {3, 3, 2};

 // Maximum demand of each process
 int maximum[MAX_PROCESSES][MAX_RESOURCES] = {
 {7, 5, 3}, // P0
 {3, 2, 2}, // P1
 {9, 0, 2}, // P2
 {2, 2, 2}, // P3
 {4, 3, 3} // P4
 };

 // Currently allocated resources
 int allocation[MAX_PROCESSES][MAX_RESOURCES] = {
 {0, 1, 0}, // P0
 {2, 0, 0}, // P1
 {3, 0, 2}, // P2
 {2, 1, 1}, // P3
 {0, 0, 2} // P4
 };

 BankerSystem banker;
 initialize_system(&banker, available, maximum, allocation, 5, 3);

 // Check initial state
 print_state(&banker);

 int safe_sequence[MAX_PROCESSES];
 if (is_safe(&banker, safe_sequence)) {
 printf("\nInitial state is SAFE\n");
 printf("Safe sequence: ");
 for (int i = 0; i < 5; i++) {
 printf("P%d ", safe_sequence[i]);
 }
 printf("\n");
 } else {
 printf("\nInitial state is UNSAFE!\n");
 }

 // Test request from P1
 printf("\n========================================\n");
 printf("P1 requests [1, 0, 2]\n");
 printf("========================================\n");
 int request1[] = {1, 0, 2};
 request_resources(&banker, 1, request1);
 print_state(&banker);

 // Test request from P4
 printf("\n========================================\n");
 printf("P4 requests [3, 3, 0]\n");
 printf("========================================\n");
 int request2[] = {3, 3, 0};
 request_resources(&banker, 4, request2);
 print_state(&banker);

 return 0;
}

import java.util.*;

/**
 * Deadlock Detection Algorithm
 * ----------------------------
 * Implements detection and recovery from deadlocks using
 * the wait-for graph approach and resource preemption.
 */
public class DeadlockDetection {

 private int numProcesses;
 private int numResources;
 private int[] available; // Available resources
 private int[][] maximum; // Maximum demand
 private int[][] allocation;// Currently allocated
 private int[][] request; // Current requests

 public DeadlockDetection(int numProcesses, int numResources, 
 int[] available, int[][] maximum) {
 this.numProcesses = numProcesses;
 this.numResources = numResources;
 this.available = available.clone();
 this.maximum = maximum;
 this.allocation = new int[numProcesses][numResources];
 this.request = new int[numProcesses][numResources];
 }

 /**
 * Allocate resources to a process
 */
 public void allocate(int processId, int[] resources) {
 for (int i = 0; i < numResources; i++) {
 allocation[processId][i] += resources[i];
 available[i] -= resources[i];
 }
 }

 /**
 * Set request vector for a process
 */
 public void setRequest(int processId, int[] resources) {
 for (int i = 0; i < numResources; i++) {
 request[processId][i] = resources[i];
 }
 }

 /**
 * Detect if system is in a deadlocked state
 * Uses Banker's-like detection algorithm for multiple resource instances
 * 
 * @return Set of deadlocked process IDs
 */
 public Set<Integer> detectDeadlock() {
 // Work = available resources
 int[] work = available.clone();

 // Finish[i] = false if we should consider process i
 boolean[] finish = new boolean[numProcesses];

 // Initialize: processes with allocation > 0 can finish
 // (simplified: we consider all processes)
 Arrays.fill(finish, false);

 // Find processes that can complete
 boolean changed;
 do {
 changed = false;
 for (int i = 0; i < numProcesses; i++) {
 if (!finish[i]) {
 // Check if request[i] <= work
 if (canSatisfy(request[i], work)) {
 // Process can complete, release resources
 for (int j = 0; j < numResources; j++) {
 work[j] += allocation[i][j];
 }
 finish[i] = true;
 changed = true;
 }
 }
 }
 } while (changed);

 // All processes with finish[i] = false are deadlocked
 Set<Integer> deadlockedProcesses = new HashSet<>();
 for (int i = 0; i < numProcesses; i++) {
 if (!finish[i]) {
 deadlockedProcesses.add(i);
 }
 }

 return deadlockedProcesses;
 }

 /**
 * Check if request can be satisfied with available work
 */
 private boolean canSatisfy(int[] requestVec, int[] work) {
 for (int i = 0; i < numResources; i++) {
 if (requestVec[i] > work[i]) {
 return false;
 }
 }
 return true;
 }

 /**
 * Recovery: Terminate a process to break deadlock
 * 
 * @param processId Process to terminate
 */
 public void terminateProcess(int processId) {
 System.out.println("Terminating process P" + processId);
 // Release all allocated resources
 for (int i = 0; i < numResources; i++) {
 available[i] += allocation[processId][i];
 allocation[processId][i] = 0;
 request[processId][i] = 0;
 }
 }

 /**
 * Recovery: Preempt resources from a process
 * 
 * @param processId Process to preempt from
 * @param resources Resources to take
 */
 public void preemptResources(int processId, int[] resources) {
 System.out.println("Preempting resources from P" + processId);
 for (int i = 0; i < numResources; i++) {
 if (resources[i] <= allocation[processId][i]) {
 allocation[processId][i] -= resources[i];
 available[i] += resources[i];
 }
 }
 }

 /**
 * Build and analyze wait-for graph for deadlock detection
 * (Simpler method for single-instance resources)
 */
 public boolean detectUsingWaitForGraph() {
 // Build adjacency list for wait-for graph
 // Edge from Pi to Pj if Pi is waiting for resource held by Pj
 List<Integer>[] waitFor = new ArrayList[numProcesses];

 for (int i = 0; i < numProcesses; i++) {
 waitFor[i] = new ArrayList<>();
 for (int j = 0; j < numProcesses; j++) {
 if (i != j) {
 // Check if Pi is waiting for resource held by Pj
 for (int r = 0; r < numResources; r++) {
 if (request[i][r] > 0 && allocation[j][r] > 0) {
 waitFor[i].add(j);
 break;
 }
 }
 }
 }
 }

 // Detect cycle using DFS
 boolean[] visited = new boolean[numProcesses];
 boolean[] recStack = new boolean[numProcesses];

 for (int i = 0; i < numProcesses; i++) {
 if (hasCycleDFS(i, waitFor, visited, recStack)) {
 return true; // Cycle found - deadlock exists
 }
 }

 return false;
 }

 /**
 * DFS helper for cycle detection in wait-for graph
 */
 private boolean hasCycleDFS(int node, List<Integer>[] waitFor,
 boolean[] visited, boolean[] recStack) {
 visited[node] = true;
 recStack[node] = true;

 for (int neighbor : waitFor[node]) {
 if (!visited[neighbor]) {
 if (hasCycleDFS(neighbor, waitFor, visited, recStack)) {
 return true;
 }
 } else if (recStack[neighbor]) {
 return true; // Cycle detected
 }
 }

 recStack[node] = false;
 return false;
 }

 /**
 * Print current system state
 */
 public void printState() {
 System.out.println("\n=== System State ===");
 System.out.print("Available: ");
 System.out.println(Arrays.toString(available));

 System.out.println("\nProcess | Allocation | Request | Need ");
 System.out.println("---------|------------|------------|------------");

 for (int i = 0; i < numProcesses; i++) {
 int[] need = new int[numResources];
 for (int j = 0; j < numResources; j++) {
 need[j] = maximum[i][j] - allocation[i][j];
 }

 System.out.printf("P%-7d|%-12s|%-12s|%-12s%n", i,
 Arrays.toString(allocation[i]),
 Arrays.toString(request[i]),
 Arrays.toString(need));
 }
 }

 public static void main(String[] args) {
 // Example: 3 processes, 2 resource types
 int[] available = {0, 0}; // Both resources in use
 int[][] maximum = {
 {2, 2}, // P0
 {2, 2}, // P1
 {2, 2} // P2
 };

 DeadlockDetection detector = new DeadlockDetection(3, 2, available, maximum);

 // Setup deadlock scenario:
 // P0 holds R0, requests R1
 // P1 holds R1, requests R0
 // P2 holds nothing, requests both
 detector.allocate(0, new int[]{1, 0}); // P0 has R0
 detector.allocate(1, new int[]{0, 1}); // P1 has R1

 detector.setRequest(0, new int[]{0, 1}); // P0 wants R1
 detector.setRequest(1, new int[]{1, 0}); // P1 wants R0
 detector.setRequest(2, new int[]{1, 1}); // P2 wants both

 detector.printState();

 // Detect deadlock
 System.out.println("\n=== Deadlock Detection ===");
 Set<Integer> deadlocked = detector.detectDeadlock();

 if (!deadlocked.isEmpty()) {
 System.out.println("DEADLOCK DETECTED!");
 System.out.println("Deadlocked processes: " + deadlocked);

 // Recovery: Terminate one process
 System.out.println("\n=== Recovery: Terminating Process ===");
 int victim = deadlocked.iterator().next();
 detector.terminateProcess(victim);

 // Check again
 deadlocked = detector.detectDeadlock();
 if (deadlocked.isEmpty()) {
 System.out.println("Deadlock resolved!");
 }
 } else {
 System.out.println("No deadlock detected.");
 }
 }
}
